// Coastal Lighthouse — BREP showcase. Single fused solid (printable):
// every junction overlaps by >=0.5mm, the lantern room seats onto the
// balcony (no mid-air gap), and the door cutter passes fully through the
// wall so no thin sliver is left behind.
const { BREP } = api;

// --- Base plinth (dark basalt) ---
const base = BREP.label(BREP.cylinder(14, 6), 'base');

// --- Door — box cut on +Y. Depth 2mm (y 12.5..14.5) so it cuts THROUGH the
// r=14 wall instead of leaving a 0.25mm detached sliver.
const doorCutter = BREP.label(
  BREP.box([3, 2, 5]).translate([0, 13.5, 0.5]),
  'door',
);
const baseWithDoor = base.cut(doorCutter);

// --- Tower stripes: 6 cylinders each 8.5mm tall, alternating labels.
const stripeLabels = ['stripeW1', 'stripeR1', 'stripeW2', 'stripeR2', 'stripeW3', 'stripeR3'];
const stripes = stripeLabels.map((lbl, i) => {
  const z = 5.5 + i * 8;
  return BREP.label(BREP.cylinder(10, 8.5).translate([0, 0, z]), lbl);
});

// --- Balcony floor — overlaps the shaft below and the lantern above.
const balconyFloor = BREP.label(
  BREP.cylinder(11.5, 2.5).translate([0, 0, 53]),
  'balcony',
);

// --- Railing torus.
const railing = BREP.label(
  BREP.torus(11, 1.2).translate([0, 0, 56]),
  'railing',
);

// --- Rail posts (8 around).
const onePost = BREP.cylinder(0.4, 4);
const postsRing = BREP.circularPattern(onePost, 8, { radius: 11 });
const posts = BREP.label(postsRing.translate([0, 0, 52.5]), 'posts');

// --- Lantern room — seated at z=54.5 so its base (r=8) overlaps the balcony
// floor (z 53..55.5) by 1mm. Previously it floated at z=57.5 above a 2mm gap.
const lantern = BREP.label(
  BREP.cylinder(8, 8.5).translate([0, 0, 54.5]),
  'lantern',
);

// --- Conical roof — overlaps the lantern top (z=63) by 0.5mm.
const roof = BREP.label(
  BREP.cone(8, 0, 6.5).translate([0, 0, 62.5]),
  'roof',
);

return BREP.fuseAll([
  baseWithDoor,
  ...stripes,
  balconyFloor,
  railing,
  posts,
  lantern,
  roof,
]);

